from typing import List


class Solution:
    def solveNQueens(self, n: int) -> List[List[str]]:
        results: List[List[str]] = []
        cols = set()
        diag1 = set()   # row - col
        diag2 = set()   # row + col
        placement: List[int] = []  # placement[r] = chosen column in row r

        def backtrack(row: int) -> None:
            if row == n:
                board = []
                for c in placement:
                    board.append("." * c + "Q" + "." * (n - c - 1))
                results.append(board)
                return
            for col in range(n):
                if col in cols or (row - col) in diag1 or (row + col) in diag2:
                    continue
                cols.add(col); diag1.add(row - col); diag2.add(row + col)
                placement.append(col)
                backtrack(row + 1)
                placement.pop()
                cols.discard(col); diag1.discard(row - col); diag2.discard(row + col)

        backtrack(0)
        return results


# ---- brute force oracle: try all n^n column assignments, validate at end ----
class BruteForce:
    def solveNQueens(self, n: int) -> List[List[str]]:
        results = []
        assignment = []

        def valid(assign):
            for a in range(len(assign)):
                for b in range(a + 1, len(assign)):
                    if assign[a] == assign[b]:
                        return False
                    if abs(assign[a] - assign[b]) == abs(a - b):
                        return False
            return True

        def gen(row):
            if row == n:
                if valid(assignment):
                    results.append(["." * c + "Q" + "." * (n - c - 1) for c in assignment])
                return
            for col in range(n):
                assignment.append(col)
                gen(row + 1)
                assignment.pop()

        gen(0)
        return results


if __name__ == "__main__":
    s = Solution()
    bf = BruteForce()

    # known solution counts for n-queens
    expected = {1: 1, 2: 0, 3: 0, 4: 2, 5: 10, 6: 4, 7: 40, 8: 92, 9: 352}

    for n in range(1, 10):
        res = s.solveNQueens(n)
        # validity check
        for board in res:
            assert len(board) == n and all(row.count("Q") == 1 and len(row) == n for row in board)
        assert len(res) == expected[n], f"n={n}: got {len(res)}, want {expected[n]}"
        # no duplicates
        assert len({tuple(b) for b in res}) == len(res), f"dupes at n={n}"

    # cross-check against brute force oracle for small n
    for n in range(1, 8):
        opt = {tuple(b) for b in s.solveNQueens(n)}
        brute = {tuple(b) for b in bf.solveNQueens(n)}
        assert opt == brute, f"mismatch vs brute at n={n}"

    print("n=4 solutions:")
    for b in s.solveNQueens(4):
        print("\n".join(b)); print()
    print("All counts:", {n: len(s.solveNQueens(n)) for n in range(1, 10)})
    print("ALL TESTS PASSED")
